import React, { useState, useEffect } from "react";
import FriendList from "./FriendList";
import NotificationList from "./NotificationList";
import ChatSocket from "./ChatSocket";
import io from 'socket.io-client';

export default function HomePage() {
  const [screen, setScreen] = useState("newfeed");
  const [input1, onChangeInput1] = useState('');
  const [input2, onChangeInput2] = useState('');
  const [toast, setToast] = useState(null);
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);
  const [notificationCount, setNotificationCount] = useState(0);
  const [comments, setComments] = useState([]);

  // 👉 Danh sách bài đăng
  const [posts, setPosts] = useState([
    {
      name: "Ngọc Anh",
      avatar: "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/oadiyd0v_expires_30_days.png",
      text: "Cảnh hôm nay đẹp quá!",
      images: [
        "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nwti4bgy_expires_30_days.png",
        "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/3cxpt7rg_expires_30_days.png"
      ]
    },
    {
      name: "Minh Khang",
      text: "Buổi học thú vị!",
      images: []
    }
  ]);

  const [socket, setSocket] = useState(null);

  const showToast = (message) => {
    setToast(message);
    setTimeout(() => setToast(null), 2500);
  };

  const getToken = () => localStorage.getItem('token');

  const fetchNotificationCount = async () => {
    try {
      const token = getToken();
      if (!token) return;

      const response = await fetch('http://localhost:3001/api/notifications', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (response.ok) {
        const data = await response.json();
        const unreadCount = data.notifications.filter(n => !n.is_read).length;
        setNotificationCount(unreadCount);
      }
    } catch (err) {
      console.error('Error fetching notification count:', err);
    }
  };

  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    const savedToken = localStorage.getItem('token');
    if (savedUser && savedToken) {
      setUser(JSON.parse(savedUser));
      setToken(savedToken);
      fetchNotificationCount();

      const newSocket = io('http://localhost:3001', {
        auth: { token: savedToken }
      });

      newSocket.on('notification', (notification) => {
        console.log('New notification received:', notification);
        fetchNotificationCount();
      });

      setSocket(newSocket);
      return () => newSocket.disconnect();
    }
  }, []);

  // Nếu không phải newfeed thì chuyển sang các màn khác
  if (screen === "friends") return <FriendList goBack={() => setScreen("newfeed")} />;
  if (screen === "notifications") {
    if (notificationCount > 0) setNotificationCount(0);
    return <NotificationList goBack={() => setScreen("newfeed")} onNotificationRead={() => fetchNotificationCount()} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-100">
      <div className="flex-1 flex flex-col">
        {/* Header cố định */}
        <div className="fixed top-0 left-0 right-0 flex items-center justify-between bg-[#88BCF8] py-3 px-6 z-50">
          <div className="flex items-center flex-shrink-0">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/iitooitd_expires_30_days.png"
              className="w-[120px] h-[110px] object-fill"
              alt="logo"
            />
          </div>

          <div className="flex items-center gap-2 max-w-[600px] w-full mx-6">
            <input
              placeholder="Nhập để tìm kiếm"
              value={input1}
              onChange={(e) => onChangeInput1(e.target.value)}
              className="text-black bg-[#F6FEFF] text-base flex-1 py-2 px-5 rounded-[50px] border-0 outline-none"
            />
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/qfk5vizv_expires_30_days.png"
              alt="search-icon"
              className="w-[30px] h-[30px] cursor-pointer hover:scale-110 transition-transform duration-200"
            />
          </div>

          <div className="flex items-center gap-5 flex-shrink-0">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ga5suwf5_expires_30_days.png"
              className="w-[30px] h-[30px] object-contain cursor-pointer hover:scale-110 transition-transform duration-200"
              alt="messenger-icon"
              onClick={() => setScreen("chat")}
            />

            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ceqzh6wh_expires_30_days.png"
              className="w-[30px] h-[30px] object-contain cursor-pointer hover:scale-110 transition-transform duration-200"
              alt="game-icon"
            />

            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/qgvtd1n2_expires_30_days.png"
              className="w-[30px] h-[30px] cursor-pointer hover:scale-110 transition"
              onClick={() => setScreen("friends")}
            />

            <button
              onClick={() => setScreen("notifications")}
              className="bg-green-500 text-white px-4 py-2 rounded-lg hover:bg-green-600 relative"
            >
              Thông báo
              {notificationCount > 0 && (
                <span className="absolute -top-2 -right-2 bg-red-500 text-white text-xs rounded-full w-5 h-5 flex items-center justify-center">
                  {notificationCount > 99 ? '99+' : notificationCount}
                </span>
              )}
            </button>
          </div>
        </div>

        {/* Nội dung chính */}
        <div className="mt-[120px] px-6 flex flex-col items-center gap-6">
          {toast && (
            <div className="fixed top-[120px] right-10 bg-black text-white px-6 py-3 rounded-lg shadow-lg z-50 animate-slide-down">
              {toast}
            </div>
          )}

          <button
            className="w-full max-w-[1000px] bg-[#FFDEF8CF] py-3 rounded-[8px] -mt-2"
            onClick={() => showToast("Xin chào bạn!")}
          >
            <span className="text-black text-xl">Chào bạn</span>
          </button>

          {/* Ô đăng bài */}
          <div className="flex items-center bg-[#A2D3FF] py-3 px-6 rounded-[10px] w-full max-w-[1000px]">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/d7m3bryx_expires_30_days.png"
              className="w-[58px] h-[58px] mr-4"
              alt="avatar"
            />
            <input
              placeholder="Hôm nay bạn thế nào chia sẻ với tui đi!!"
              value={input2}
              onChange={(e) => onChangeInput2(e.target.value)}
              className="text-black bg-[#F6FEFF] text-xl flex-1 py-2 px-4 rounded-[50px] border-0"
            />
            <button
              className="ml-4 bg-blue-400 text-white px-4 py-2 rounded-lg"
              onClick={() => {
                if (input2.trim() !== "") {
                  showToast(`Bạn vừa gửi: "${input2}"`);
                  setPosts([{ name: user?.name || "Bạn", text: input2, images: [] }, ...posts]);
                  onChangeInput2('');
                  setTimeout(() => showToast("Bài đăng mới của bạn đã được thêm!"), 500);
                }
              }}
            >
              Gửi
            </button>
          </div>

          {/* Danh sách bài đăng */}
          {posts.map((post, i) => (
            <div key={i} className="flex flex-col bg-[#A2D3FF] w-full max-w-[1000px] p-4 rounded-[10px] gap-4">
              <div className="flex items-center gap-4">
                <img
                  src={post.avatar || "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/oadiyd0v_expires_30_days.png"}
                  className="w-[58px] h-[51px]"
                  alt="avatar"
                />
                <div className="flex flex-col">
                  <span className="text-black text-xl">{post.name}</span>
                  <span className="text-black text-base">công khai</span>
                </div>
              </div>

              {post.text && <p className="text-black text-lg">{post.text}</p>}

              {post.images?.length > 0 && (
                <div className="flex gap-4">
                  {post.images.map((img, idx) => (
                    <img key={idx} src={img} className="w-1/2 rounded-lg" alt={`post-${idx}`} />
                  ))}
                </div>
              )}

              <div className="flex items-center gap-2 mt-2">
                <input
  type="file"
  accept="image/*"
  onChange={(e) => setSelectedFile(e.target.files[0])}
  className="text-black"
/>
                <input
                  placeholder="Bình luận"
                  value={comments[i]?.input || ''}
                  onChange={(e) => {
                    const newComments = [...comments];
                    if (!newComments[i]) newComments[i] = { input: '', list: [] };
                    newComments[i].input = e.target.value;
                    setComments(newComments);
                  }}
                  className="flex-1 py-2 px-4 rounded-lg text-black border-0"
                />
                <button
                  className="bg-blue-500 text-white px-3 py-1 rounded-lg"
                  onClick={() => {
                    if (!comments[i]?.input?.trim()) return;
                    const newComments = [...comments];
                    if (!newComments[i].list) newComments[i].list = [];
                    newComments[i].list.push(newComments[i].input);
                    newComments[i].input = '';
                    setComments(newComments);
                  }}
                >
                  Gửi
                </button>
              </div>

              {comments[i]?.list?.length > 0 && (
                <div className="mt-2 ml-12 flex flex-col gap-1">
                  {comments[i].list.map((cmt, idx) => (
                    <span key={idx} className="text-black text-sm bg-white px-2 py-1 rounded-lg">
                      {cmt}
                    </span>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      <style>
        {`
          @keyframes slideDown {
            0% { opacity: 0; transform: translateY(-20px); }
            100% { opacity: 1; transform: translateY(0); }
          }
          .animate-slide-down {
            animation: slideDown 0.3s ease-out;
          }
        `}
      </style>
    </div>
  );
}
